#!/usr/bin/env node
const require_run = require("./run-pQFYI5zn.cjs");
let node_util = require("node:util");
//#region src/cli.ts
try {
	process.loadEnvFile();
} catch {}
const HELP = `Usage: extensions-cli <command> [options] [dir]

Commands:
  run [dir]         Run an extension in Live's Extension Host. Reads
                    EXTENSION_HOST_PATH from the environment (or .env).
                    Options:
                      --live <path>          Override EXTENSION_HOST_PATH
                      --storage-directory <path>
                      --temp-directory <path>
                      --inspect              Enable VS Code debugging (--inspect-brk)

  package [dir]     Build a .ablx archive from a built extension.
                    Options:
                      -o, --output <path>    Output .ablx path
                      -i, --include <p...>   Additional files/dirs to bundle

  help              Show this message
`;
function printHelpAndExit(code) {
	process.stdout.write(HELP);
	process.exit(code);
}
async function main(argv) {
	const [command, ...rest] = argv;
	if (!command || command === "help" || command === "-h" || command === "--help") printHelpAndExit(command ? 0 : 1);
	switch (command) {
		case "run": {
			const { values, positionals } = (0, node_util.parseArgs)({
				args: rest,
				allowPositionals: true,
				options: {
					live: { type: "string" },
					"storage-directory": { type: "string" },
					"temp-directory": { type: "string" },
					inspect: { type: "boolean" }
				}
			});
			const live = values.live ?? process.env.EXTENSION_HOST_PATH;
			if (!live) {
				console.error("No Extension Host path provided.\nSet EXTENSION_HOST_PATH in your environment (e.g. in a .env file) or pass --live <path>.");
				process.exit(1);
			}
			require_run.runExtension(positionals[0], {
				live,
				...values["storage-directory"] !== void 0 && { storageDirectory: values["storage-directory"] },
				...values["temp-directory"] !== void 0 && { tempDirectory: values["temp-directory"] },
				...values.inspect && { inspect: true }
			});
			return;
		}
		case "package": {
			const { values, positionals } = (0, node_util.parseArgs)({
				args: rest,
				allowPositionals: true,
				options: {
					output: {
						type: "string",
						short: "o"
					},
					include: {
						type: "string",
						short: "i",
						multiple: true
					}
				}
			});
			await require_run.packageExtension(positionals[0], values.output, values.include);
			return;
		}
		default:
			console.error(`Unknown command: ${command}\n`);
			printHelpAndExit(1);
	}
}
main(process.argv.slice(2)).catch((err) => {
	console.error(err instanceof Error ? err.message : err);
	process.exit(1);
});
//#endregion
